     */
    public static List<Integer> naiveInsert(int dataSize) {
        List<Integer> list = new ArrayList<>(); // capacity=10으로 초기화

        for (int i = 0; i < dataSize; i++) {
            list.add(i); // capacity 초과마다 grow() + arraycopy 발생
        }
        return list;
    }

    /**
