    // Case 1: 초기 용량 미지정 (기본값 10) → 다수의 재할당 발생
    static void benchmarkWithoutCapacity() {
        long start = System.nanoTime();

        ArrayList<Integer> list = new ArrayList<>(); // 초기 용량 10
        for (int i = 0; i < DATA_SIZE; i++) {
