        }

        long elapsed = System.nanoTime() - start;
        System.out.printf("[초기 용량 지정]    소요 시간: %,d ns%n", elapsed);
    }

    // Case 3: ensureCapacity() 런타임 동적 예약
    static void benchmarkEnsureCapacity() {
        long start = System.nanoTime();

        ArrayList<Integer> list = new ArrayList<>();
        list.ensureCapacity(DATA_SIZE); // 단일 재할당으로 목표 용량 확보
        for (int i = 0; i < DATA_SIZE; i++) {
            list.add(i);
        }

