        System.out.printf("[ensureCapacity]   소요 시간: %,d ns%n", elapsed);
    }

    // Case 4: LinkedList → 노드별 힙 할당, GC 압력 증가
    static void benchmarkLinkedList() {
        long start = System.nanoTime();

        LinkedList<Integer> list = new LinkedList<>();
        for (int i = 0; i < DATA_SIZE; i++) {
            list.add(i);
        }

        long elapsed = System.nanoTime() - start;
        System.out.printf("[LinkedList]       소요 시간: %,d ns%n", elapsed);
        // 노드당 헤더(16B) + prev/next 포인터(16B) + 데이터 참조(4B) = ~36B 오버헤드
    }
}
```

### 2. 재할당 횟수 추적 (리플렉션 활용)

```java
import java.lang.reflect.Field;
import java.util.ArrayList;

public class CapacityTracker {

    /**
     * 리플렉션으로 elementData.length (실제 할당 용량) 추출
     * ArrayList는 size(논리적 크기)와 capacity(물리적 배열 크기)를 분리 관리
     */
    static int getCapacity(ArrayList<?> list) throws Exception {
        Field field = ArrayList.class.getDeclaredField("elementData");
        field.setAccessible(true);
        Object[] elementData = (Object[]) field.get(list);
        return elementData.length;
    }

    public static void main(String[] args) throws Exception {
        ArrayList<Integer> list = new ArrayList<>(); // 초기 capacity = 10
        int prevCapacity = getCapacity(list);
        int reallocCount = 0;

        System.out.println("=== 재할당 이벤트 추적 ===");
        System.out.printf("초기 capacity: %d%n", prevCapacity);

        for (int i = 0; i < 200; i++) {
            list.add(i);
            int currCapacity = getCapacity(list);

            if (currCapacity != prevCapacity) {
                reallocCount++;
                System.out.printf(
                    "재할당 #%2d | size: %3d | %3d → %3d (증가율: %.1f%%)%n",
                    reallocCount, list.size(),
                    prevCapacity, currCapacity,
                    (double)(currCapacity - prevCapacity) / prevCapacity * 100
                );
                prevCapacity = currCapacity;
            }
        }
        System.out.printf("%n총 재할당 횟수: %d회%n", reallocCount);
    }
}
```

