#### 기법 2: 현재 시점에서 Autoboxing 오버헤드 최소화

```java
import java.util.function.IntConsumer;
import java.util.function.IntSupplier;

/**
 * int primitive 특화 스택 구현.
 * Generic Stack<Integer> 대비 autoboxing 제거로
 * GC pressure 및 heap fragmentation 감소.
 *
 * 측정 기준:
 *  - Integer 객체: 16 bytes (object header 12 + int field 4)
 *  - int primitive: 4 bytes
 *  - 10만 원소 기준 약 1.2MB vs 400KB
 */
public final class PrimitiveIntStack {

    private int[] data;
    private int   top;

    public PrimitiveIntStack(int initialCapacity) {
        this.data = new int[initialCapacity];
        this.top  = -1;
    }

    public void push(int value) {
        ensureCapacity();
        data[++top] = value;
    }

    public int pop() {
        if (top < 0) throw new java.util.EmptyStackException();
        return data[top--];
    }

    public int peek() {
        if (top < 0) throw new java.util.EmptyStackException();
        return data[top];
    }

    public int size()    { return top + 1; }
    public boolean isEmpty() { return top < 0; }

    private void ensureCapacity() {
        if (top + 1 == data.length) {
            // Arrays.copyOf: System.arraycopy 기반, JIT에 의해
            // intrinsic으로 최적화됨 (JVM intrinsic: arraycopy)
            data = java.util.Arrays.copyOf(data, data.length * 2);
        }
    }

    /**
     * 전체 원소를 IntConsumer로 소비.
     * Iterator<Integer> 대비 Integer 객체 생성 없이
     * 순회 가능 → minor GC 트리거 빈도 감소.
     */
    public void forEach(IntConsumer action) {
        for (int i = 0; i <= top; i++) {
            action.accept(data[i]);
        }
    }
}
```

