### Bytecode 수준 검증

```java
import java.lang.reflect.*;
import java.util.*;

public class TypeErasureInspector {

    /**
     * 런타임에서 타입 소거 결과를 JVM Reflection API로 검증
     * - getGenericType(): 소거 전 타입 정보 (ParameterizedType)
     * - getType(): 소거 후 타입 정보 (raw type)
     */
    public static void inspectErasure(Class<?> clazz) {
        System.out.println("=== Type Erasure Inspection: " + clazz.getName() + " ===");

        for (Field field : clazz.getDeclaredFields()) {
            Type genericType = field.getGenericType();   // 소거 전 (메타데이터)
            Class<?> erasedType = field.getType();        // 소거 후 (실제 바이트코드)

            System.out.printf(
                "Field: %-20s | Generic(metadata): %-30s | Erased(bytecode): %s%n",
                field.getName(),
                genericType.getTypeName(),
                erasedType.getName()
            );
        }

        for (Method method : clazz.getDeclaredMethods()) {
            // isBridge(): 컴파일러가 타입 소거 호환성을 위해 삽입한 bridge method 식별
            if (method.isBridge()) {
                System.out.println("Bridge Method (synthetic): " + method);
            }
            if (method.isSynthetic()) {
                System.out.println("Synthetic Method: " + method);
            }
        }
    }

    // 테스트용 제네릭 클래스
    static class Container<T extends Number> {
        private T element;
        private List<T> elements;
        private Map<String, T> mapping;

        public T get() { return element; }
        public List<T> getAll() { return elements; }
    }

    public static void main(String[] args) {
        inspectErasure(Container.class);

        // 소거로 인한 런타임 타입 동일성 확인
        List<String> strList = new ArrayList<>();
        List<Integer> intList = new ArrayList<>();

        // 소거 후 동일한 Class 객체 → 힙에 Class 메타데이터 중복 없음
        System.out.println("\nList<String>.class == List<Integer>.class: " 
            + (strList.getClass() == intList.getClass())); // true

        // 그러나 개별 원소는 여전히 Object로 boxing → 힙 오버헤드 존재
        System.out.println("Element type at runtime: " 
            + strList.getClass().getTypeParameters()[0]); // T (소거됨)
    }
}
```

