                    CumulativeVisibilityProbability = 0f,
                    ObservationCount = 0,
                    ExponentialMovingAverage = 0.5f,
                    Variance = 0.25f,
                    ConsecutiveOcclusionFrames = 0
                };
            }
            _sectorToRenderers[sector].Add(renderer);
        }

