        {
            _sectorStatistics[sector] = record;
        }

        public List<SpriteRenderer> GetRenderersInSector(Vector2Int sector)
        {
            return _sectorToRenderers.TryGetValue(sector, out var list) ? list : null;
        }

        public float SectorSize => _sectorSize;
    }
