    /// 각 Chunk는 독립적인 TilemapRenderer를 가지므로
    /// 개별 Draw Call 단위로 컬링이 가능합니다.
    /// </summary>
    void InitializeChunks()
    {
        // 원본 Tilemap의 전체 사용 영역 계산
        targetTilemap.CompressBounds();
        BoundsInt tilemapBounds = targetTilemap.cellBounds;

        int startX = tilemapBounds.xMin;
        int startY = tilemapBounds.yMin;
        int endX = tilemapBounds.xMax;
        int endY = tilemapBounds.yMax;

        // Chunk 단위로 분할
        for (int x = startX; x < endX; x += chunkSize)
        {
            for (int y = startY; y < endY; y += chunkSize)
            {
                int chunkEndX = Mathf.Min(x + chunkSize, endX);
                int chunkEndY = Mathf.Min(y + chunkSize, endY);

                BoundsInt chunkTileBounds = new BoundsInt(
                    x, y, 0,
                    chunkEndX - x,
                    chunkEndY - y,
                    1
                );

