                // 빈 Chunk에 대한 불필요한 GameObject 생성 방지
                if (!HasAnyTileInBounds(chunkTileBounds))
                    continue;

                TilemapChunk chunk = CreateChunkObject(chunkTileBounds);
                chunks.Add(chunk);
            }
        }

        Debug.Log($"[TilemapChunkCuller] 총 {chunks.Count}개 Chunk 생성 완료");

        // 원본 Tilemap 렌더러 비활성화 (Chunk 렌더러로 대체)
        TilemapRenderer originalRenderer = targetTilemap.GetComponent<TilemapRenderer>();
        if (originalRenderer != null)
            originalRenderer.enabled = false;
    }

