## 1. STC 알고리즘 구현 (Unity C#)

```csharp
using System.Collections.Generic;
using UnityEngine;
using UnityEngine.Tilemaps;

[RequireComponent(typeof(Tilemap))]
public class StochasticTilemapCuller : MonoBehaviour
{
    [Header("Culling Parameters")]
    [SerializeField] private Camera targetCamera;
    [SerializeField, Range(0f, 1f)] private float baseCullProbability = 0.15f;
    [SerializeField] private float frustumPadding = 1.0f;
    [SerializeField] private int maxDrawCallBudget = 2048;
    [SerializeField] private float temporalDecay = 0.85f;

    private Tilemap tilemap;
    private Plane[] frustumPlanes = new Plane[6];
    private Dictionary<Vector3Int, float> visibilityWeight = new();
    private Dictionary<Vector3Int, TileBase> cachedTiles = new();

    void Awake()
    {
        tilemap = GetComponent<Tilemap>();
        if (targetCamera == null) targetCamera = Camera.main;
        CacheActiveTiles();
    }

    private void CacheActiveTiles()
    {
        foreach (var pos in tilemap.cellBounds.allPositionsWithin)
        {
            var t = tilemap.GetTile(pos);
            if (t != null) cachedTiles[pos] = t;
        }
    }

    void LateUpdate()
    {
        GeometryUtility.CalculateFrustumPlanes(targetCamera, frustumPlanes);

        // 1) 프러스텀 내 후보 셀 추출 (Broad-phase)
        var candidates = ExtractFrustumCandidates();

        // 2) 중요도 가중치 산출 (드로우 콜 예산 기반 동적 확률)
        float density = candidates.Count / (float)maxDrawCallBudget;
        float dynamicProb = Mathf.Clamp01(baseCullProbability * density);

        // 3) Stochastic Rejection Sampling
        foreach (var pos in candidates)
        {
            float importance = ComputeImportance(pos);
            float survivalChance = Mathf.Lerp(0.2f, 1.0f, importance);
            float cullRoll = HashedRandom(pos, Time.frameCount / 4);

            // 시간적 일관성: 직전 프레임 가시 가중치 보존
            float prevWeight = visibilityWeight.TryGetValue(pos, out var w) ? w : 0f;
            float currentWeight = (cullRoll < survivalChance * (1f - dynamicProb))
                                  ? 1f : 0f;
            float blended = Mathf.Max(currentWeight,
                                      prevWeight * temporalDecay);
            visibilityWeight[pos] = blended;

            // 4) 파이프라인 제어: TileFlags.LockColor + 알파 0 으로 batching 유지
            ApplyVisibility(pos, blended > 0.05f);
        }
    }

    private List<Vector3Int> ExtractFrustumCandidates()
    {
        var list = new List<Vector3Int>();
        var bounds = tilemap.cellBounds;
        Vector3 cell = tilemap.cellSize;

        foreach (var pos in bounds.allPositionsWithin)
        {
            if (!cachedTiles.ContainsKey(pos)) continue;
            Vector3 world = tilemap.CellToWorld(pos);
            var aabb = new Bounds(world + cell * 0.5f, cell + Vector3.one * frustumPadding);
            if (GeometryUtility.TestPlanesAABB(frustumPlanes, aabb))
                list.Add(pos);
        }
        return list;
    }

    private float ComputeImportance(Vector3Int pos)
    {
        // 카메라 forward 축에 대한 NDC 중심 근접도 기반 중요도
        Vector3 world = tilemap.CellToWorld(pos);
        Vector3 vp = targetCamera.WorldToViewportPoint(world);
        float cx = Mathf.Abs(vp.x - 0.5f);
        float cy = Mathf.Abs(vp.y - 0.5f);
        return 1f - Mathf.Clamp01(Mathf.Sqrt(cx * cx + cy * cy) * 2f);
    }

