# 멀티스레드 환경에서의 Thread-Safe Queue 구현

## 1. 구현 코드

```java
import java.util.Vector;
import java.util.NoSuchElementException;

/**
 * java.util.Vector를 내부 저장소로 사용하는 Thread-Safe Queue
 * FIFO(First-In-First-Out) 정책을 따른다.
 */
public class ThreadSafeVectorQueue<E> {

    private final Vector<E> storage;

    public ThreadSafeVectorQueue() {
        this.storage = new Vector<>();
    }

    public ThreadSafeVectorQueue(int initialCapacity) {
        this.storage = new Vector<>(initialCapacity);
    }

    /**
     * enqueue: Vector의 말단에 원소를 적재한다.
     * Vector.add()는 synchronized 메서드이므로 임계 영역(critical section)이 자동 보장된다.
     */
    public boolean enqueue(E element) {
        if (element == null) {
            throw new NullPointerException("null 원소는 허용되지 않는다.");
        }
        return storage.add(element);
    }

    /**
     * dequeue: Vector의 선두에서 원소를 제거 후 반환한다.
     * 단일 원자 연산(atomic operation)이 아닌 복합 연산(check-then-act)이므로
     * 외부 동기화(client-side locking)를 추가로 적용한다.
     */
    public E dequeue() {
        synchronized (storage) {
            if (storage.isEmpty()) {
                throw new NoSuchElementException("Queue가 비어 있다.");
            }
            return storage.remove(0);
        }
    }

    /**
     * peek: 선두 원소를 제거 없이 조회한다. 복합 연산이므로 외부 동기화 필요.
     */
    public E peek() {
        synchronized (storage) {
            if (storage.isEmpty()) {
                return null;
            }
            return storage.firstElement();
        }
    }

    public int size() {
        return storage.size();
    }

    public boolean isEmpty() {
        return storage.isEmpty();
    }
}
```

## 2. 사용 예시 (Producer-Consumer)

```java
public class PipelineDemo {
    public static void main(String[] args) throws InterruptedException {
        ThreadSafeVectorQueue<Integer> queue = new ThreadSafeVectorQueue<>();

        // Producer Thread
        Thread producer = new Thread(() -> {
            for (int i = 0; i < 1000; i++) {
                queue.enqueue(i);
            }
        });

        // Consumer Thread
        Thread consumer = new Thread(() -> {
            int count = 0;
            while (count < 1000) {
                try {
                    Integer v = queue.dequeue();
                    count++;
                } catch (Exception e) {
                    Thread.yield();
                }
            }
        });

        producer.start();
        consumer.start();
        producer.join();
        consumer.join();
    }
}
```

