## 1. 매니저 클래스 구현

```csharp
using System.Collections.Generic;
using UnityEngine;
using UnityEngine.Tilemaps;

public sealed class ResourceManager : MonoBehaviour
{
    public static ResourceManager Instance { get; private set; }

    // 타입별 캐시 컨테이너: 키는 Resources 경로, 값은 UnityEngine.Object 참조
    private readonly Dictionary<string, Object> _assetCache 
        = new Dictionary<string, Object>(1024);

    // 참조 카운트: 동일 에셋에 대한 다중 요청 추적
    private readonly Dictionary<string, int> _refCount 
        = new Dictionary<string, int>(1024);

    private void Awake()
    {
        if (Instance != null && Instance != this) { Destroy(gameObject); return; }
        Instance = this;
        DontDestroyOnLoad(gameObject);
    }

    /// <summary>
    /// 동기적 Resources.Load 호출. 캐시 미스 시 디스크 I/O 발생.
    /// </summary>
    public T Load<T>(string path) where T : Object
    {
        if (_assetCache.TryGetValue(path, out Object cached))
        {
            _refCount[path]++;
            return cached as T;
        }

        T asset = Resources.Load<T>(path);
        if (asset == null)
        {
            Debug.LogError($"[ResourceManager] Load failed: {path}");
            return null;
        }

        _assetCache.Add(path, asset);
        _refCount.Add(path, 1);
        return asset;
    }

    public Sprite LoadSprite(string path)   => Load<Sprite>(path);
    public TileBase LoadTile(string path)   => Load<TileBase>(path);
    public GameObject LoadPrefab(string path) => Load<GameObject>(path);

    /// <summary>
    /// 참조 카운트 감소. 0 도달 시 캐시 엔트리 제거.
    /// 실제 언로드는 Resources.UnloadUnusedAssets() 또는 UnloadAsset()으로 수행.
    /// </summary>
    public void Release(string path)
    {
        if (!_refCount.ContainsKey(path)) return;

        _refCount[path]--;
        if (_refCount[path] <= 0)
        {
            Object obj = _assetCache[path];
            _assetCache.Remove(path);
            _refCount.Remove(path);

            // GameObject(프리팹)는 UnloadAsset 불가 → UnloadUnusedAssets에 의존
            if (!(obj is GameObject) && !(obj is Component))
                Resources.UnloadAsset(obj);
        }
    }

    public void UnloadAll()
    {
        _assetCache.Clear();
        _refCount.Clear();
        Resources.UnloadUnusedAssets();
        System.GC.Collect();
    }
}
```

