## 3. 매니저 클래스 구현
```csharp
public class AssetResourceManager : MonoBehaviour
{
    private static Dictionary<string, Object> _assetCache = new Dictionary<string, Object>();
    private static Dictionary<string, int> _referenceCount = new Dictionary<string, int>();
    private static Dictionary<string, System.Type> _assetTypeRegistry = new Dictionary<string, System.Type>();

    // 에셋 타입 등록
    public static void RegisterAssetType(string assetPath, System.Type assetType)
    {
        if (!_assetTypeRegistry.ContainsKey(assetPath))
        {
            _assetTypeRegistry.Add(assetPath, assetType);
        }
    }

    // 동기적 에셋 로드 및 캐싱
    public static T LoadAsset<T>(string resourcePath) where T : Object
    {
        // 캐시 확인
        if (_assetCache.ContainsKey(resourcePath))
        {
            Object cachedAsset = _assetCache[resourcePath];
            if (cachedAsset is T typedAsset)
            {
                IncrementReferenceCount(resourcePath);
                return typedAsset;
            }
            else
            {
                Debug.LogError($"Type mismatch for cached asset: {resourcePath}");
                return null;
            }
        }

        // Resources 동기 로드
        T loadedAsset = Resources.Load<T>(resourcePath);
        if (loadedAsset == null)
        {
            Debug.LogError($"Failed to load asset: {resourcePath}");
            return null;
        }

        // 캐시 저장
        _assetCache.Add(resourcePath, loadedAsset);
        _referenceCount.Add(resourcePath, 1);

        // 타입 등록
        if (!_assetTypeRegistry.ContainsKey(resourcePath))
        {
            _assetTypeRegistry.Add(resourcePath, typeof(T));
        }

        return loadedAsset;
    }

    // 참조 카운트 증가
    private static void IncrementReferenceCount(string resourcePath)
    {
        if (_referenceCount.ContainsKey(resourcePath))
        {
            _referenceCount[resourcePath]++;
        }
    }

    // 에셋 참조 해제
    public static void ReleaseAsset(string resourcePath)
    {
        if (!_referenceCount.ContainsKey(resourcePath))
            return;

        _referenceCount[resourcePath]--;

        if (_referenceCount[resourcePath] <= 0)
        {
            UnloadAsset(resourcePath);
        }
    }

    // 에셋 완전 해제
    private static void UnloadAsset(string resourcePath)
    {
        if (_assetCache.ContainsKey(resourcePath))
        {
            Object asset = _assetCache[resourcePath];

            // 캐시 제거
            _assetCache.Remove(resourcePath);
            _referenceCount.Remove(resourcePath);
            _assetTypeRegistry.Remove(resourcePath);

            // Resources 언로드는 실제로 메모리에서 제거하지 않음
            // 참조가 없어지면 가비지 컬렉션 대상이 됨
        }
    }

    // 강제 언로드 (모든 참조 무시)
    public static void ForceUnloadAsset(string resourcePath)
    {
        UnloadAsset(resourcePath);
    }

    // 상태 모니터링
    public static void LogAssetStatus()
    {
        Debug.Log($"Cached Assets: {_assetCache.Count}");
        foreach (var kvp in _referenceCount)
        {
            Debug.Log($"Asset: {kvp.Key}, References: {kvp.Value}");
        }
    }

    // 씬 전환 시 정리
    public static void CleanupUnusedAssets()
    {
        List<string> toRemove = new List<string>();

        foreach (var kvp in _referenceCount)
        {
            if (kvp.Value <= 0)
            {
                toRemove.Add(kvp.Key);
            }
        }

        foreach (string path in toRemove)
        {
            UnloadAsset(path);
        }

        // 메모리 최적화
        Resources.UnloadUnusedAssets();
    }
}
```

## 4. 메모리 구조의 작동 원리

### 4.1 에셋 로딩 프로세스
1. **경로 해석**: `Resources.Load` 호출 시 Unity는 빌드된 애플리케이션 데이터 내 Resources 폴더 계층 구조에서 지정된 상대 경로를 탐색한다.
2. **직렬화된 에셋 접근**: 에셋 데이터는 애플리케이션 빌드 시 .assets 파일에 직렬화되어 저장되며, 런타임에 이진 데이터로부터 역직렬화된다.
3. **메모리 할당**: 로드된 에셋은 관리되는 힙(Managed Heap)에 인스턴스화되며, Unity 엔진의 네이티브 메모리 영역에 텍스처 데이터가 할당된다.

### 4.2 캐싱 메커니즘
- **사전 기반 캐시**: `Dictionary<string, Object>` 구조체는 해시 테이블로 구현되어 O(1) 평균 시간 복잡도로 에셋 접근을 제공한다.
- **타입 안정성**: 제네릭 타입 매개변수 `T`와 `is` 연산자를 통해 타입 일관성을 보장한다.
- **참조 카운팅**: 각 에셋에 대한 활성 참조 수를 추적하여 사용 중인 에셋의 조기 해제를 방지한다.

### 4.3 메모리 관리
1. **참조 유지**: 캐시 사전이 에셋 객체에 대한 강한 참조(Strong Reference)를 유지하여 가비지 컬렉션 대상이 되지 않도록 한다.
2. **해제 조건**: 참조 카운트가 0 이하일 때 캐시에서 제거되며, 이후 해당 객체는 다른 활성 참조가 없는 경우 가비지 컬렉션 대상이 된다.
3. **명시적 해제**: `Resources.UnloadUnusedAssets()` 호출 시 더 이상 참조되지 않는 에셋의 네이티브 메모리가 해제된다.

### 4.4 성능 특성
- **동기 로딩**: `Resources.Load`는 호출 스레드를 블로킹하며 직렬화된 에셋 데이터를 동기적으로 메모리로 로드한다.
- **메모리 오버헤드**: 사전 구조는 추가 메모리를 소비하지만(평균 O(n)), 에셋 재로딩 오버헤드를 제거한다.
- **스레드 안전성**: 정적 사전은 기본적으로 스레드 안전하지 않으므로 멀티스레드 접근 시 동기화 메커니즘이 필요하다.

### 4.5 제한사항
- `Resources` 시스템은 빌드 시 모든 Resources 폴더 내용을 단일 연속 메모리 영역에 패키징하므로, 초기 메모리 사용량이 증가한다.
- 동기 로딩은 대용량 에셋 로드 시 프레임 지연을 유발할 수 있다.
- 참조 카운팅은 순환 참조를 자동으로 처리하지 않으므로, 개발자가 수동으로 참조 관계를 관리해야 한다.

이 설계는 에셋의 생명주기를 명시적으로 제어하며, 메모리 사용량을 실시간으로 모니터링하고 최적화할 수 있는 기반을 제공한다.

## 1. 설계 개요

Unity 2D 탑뷰 게임에서 런타임에 수천 개의 타일맵(Tilemap) 자산 및 스프라이트(Sprite) 자산을 동기적으로 로드하고 관리하기 위해 `Resources` 폴더와 `Resources.Load` API만을 사용하는 정적(static) 매니저 클래스를 설계한다.  
이 클래스는 **중앙 집중형 캐시(Centralized Cache)** 역할을 수행하며, 자산의 메모리 할당 상태를 추적하고 중복 로딩을 방지하여 즉각적인 상태 업데이트(Immediate State Update)를 보장한다.

## 2. C# 매니저 클래스 구현

