    private static Dictionary<string, TileBase> tileCache = new Dictionary<string, TileBase>();
    private static Dictionary<string, Sprite> spriteCache = new Dictionary<string, Sprite>();
    // 필요 시 추가 타입에 대한 캐시 확장 가능 (예: GameObject, Texture2D 등)

    /// <summary>
    /// 동기적으로 Resources 폴더에서 에셋을 로드하고, 캐시에 저장 후 반환.
    /// 이미 캐시에 존재하는 경우 즉시 캐시된 인스턴스를 반환.
    /// </summary>
    /// <typeparam name="T">UnityEngine.Object의 서브클래스 (TileBase, Sprite 등)</typeparam>
    /// <param name="path">Resources 폴더 기준 상대 경로 (확장자 제외)</param>
    /// <returns>로드된 또는 캐시된 에셋의 인스턴스</returns>
    public static T Load<T>(string path) where T : UnityEngine.Object
    {
        // 타입에 따라 적절한 캐시 딕셔너리를 선택 (여기서는 간략화를 위해 switch 사용)
        if (typeof(T) == typeof(TileBase))
        {
            if (tileCache.TryGetValue(path, out TileBase tile))
                return tile as T;
            TileBase loadedTile = Resources.Load<TileBase>(path);
            if (loadedTile != null)
                tileCache[path] = loadedTile;
            return loadedTile as T;
        }
        else if (typeof(T) == typeof(Sprite))
        {
            if (spriteCache.TryGetValue(path, out Sprite sprite))
                return sprite as T;
            Sprite loadedSprite = Resources.Load<Sprite>(path);
            if (loadedSprite != null)
                spriteCache[path] = loadedSprite;
            return loadedSprite as T;
        }
        else
        {
            // 제네릭으로 직접 처리 (필요 시 다른 타입에 대한 캐시 추가)
            // Resources.Load는 내부적으로 이미 한 번 로드된 에셋에 대해 같은 인스턴스를 반환하지만,
            // 우리의 캐시가 명시적 참조를 유지해 가비지 컬렉션으로부터 보호한다.
            return Resources.Load<T>(path);
        }
    }

