    /// TileBase 에셋에 대한 편의 메서드
    /// </summary>
    public static TileBase LoadTile(string path) => Load<TileBase>(path);

    /// <summary>
    /// Sprite 에셋에 대한 편의 메서드
    /// </summary>
    public static Sprite LoadSprite(string path) => Load<Sprite>(path);

