    private readonly Dictionary<Type, Dictionary<string, UnityEngine.Object>> _assetCache 
        = new Dictionary<Type, Dictionary<string, UnityEngine.Object>>();

    /// <summary>
    /// Resources 폴더로부터 지정된 타입의 에셋을 동기적으로 로드하여 메모리에 할당하고 캐싱합니다.
    /// </summary>
    /// <typeparam name="T">UnityEngine.Object를 상속받는 에셋 타입</typeparam>
    /// <param name="path">Resources 폴더 기준의 상대 경로</param>
    /// <returns>로드된 에셋의 참조</returns>
    public T Load<T>(string path) where T : UnityEngine.Object
    {
        Type type = typeof(T);

