    [[nodiscard]] const std::string& get_descriptor() const noexcept;
    [[nodiscard]] bool          is_valid()        const noexcept;

    void invalidate() noexcept;

private:
    ResourceID  id_;
    std::string descriptor_;
    bool        valid_;
};

} // namespace ownership
