    // =========================================================
    // 상태 저장: 게이트 수준 SR-래치 기반 레지스터
    // 플립플롭이 아닌 교차결합 NOR 게이트로 구성
    // =========================================================

    wire [7:0] Q;       // 래치 출력 (현재 상태)
    wire [7:0] Q_bar;   // 래치 보수 출력
    wire [7:0] next;    // 다음 상태 (조합 논리 연산 결과)

    // ---------------------------------------------------------
    // 단계 1: 순수 조합 논리로 다음 상태 계산 (8비트 리플 가산)
    // next = Q + 1 (현재 상태에 1을 가산)
    // ---------------------------------------------------------
    wire [7:0] carry;

    // Half-adder 체인으로 +1 증분기(incrementer) 구현
    // 최하위 비트: XOR with 1 = NOT
    assign next[0] = ~Q[0];
    assign carry[0] = Q[0];  // AND with 1 = identity

    // 상위 비트: 리플 캐리 증분기
    genvar i;
    generate
        for (i = 1; i < 8; i = i + 1) begin : INCREMENT
            assign next[i]  = Q[i] ^ carry[i-1];
            assign carry[i] = Q[i] & carry[i-1];
        end
    endgenerate

    // ---------------------------------------------------------
    // 단계 2: 펄스 에지 검출 (조합 게이트 + 전파 지연 이용)
    // ---------------------------------------------------------
    wire pulse_delayed;
    wire set_enable;
    wire reset_enable;

    // 게이트 체인에 의한 전파 지연 생성 (버퍼 체인)
    wire d1, d2, d3, d4, d5, d6;

    // NOT 게이트 체인으로 지연 생성 (짝수 개 = 비반전 지연)
    not #1 (d1, pulse);
    not #1 (d2, d1);
    not #1 (d3, d2);
    not #1 (d4, d3);
    not #1 (d5, d4);
    not #1 (d6, d5);
    assign pulse_delayed = d6;  // pulse의 지연된 복사본

    // 상승 에지 검출: pulse AND (NOT pulse_delayed)
    // pulse가 0→1 전이 시, 짧은 구간 동안 set_enable = 1
    assign set_enable = pulse & (~pulse_delayed);

    // ---------------------------------------------------------
    // 단계 3: 게이트 수준 SR-래치 배열 (상태 저장 소자)
    // 각 비트에 대해 교차결합 NOR 게이트로 1비트 래치 구성
    // ---------------------------------------------------------

    generate
        for (i = 0; i < 8; i = i + 1) begin : LATCH_ARRAY
            wire S, R;

            // Set: 다음 상태가 1이고 에지 검출 활성 시
            // Reset: 다음 상태가 0이고 에지 검출 활성 시, 또는 전역 리셋
            assign S = (set_enable & next[i]) & ~reset;
            assign R = (set_enable & ~next[i]) | reset;

            // 교차결합 NOR 게이트 SR-래치
            // Q = NOR(R, Q_bar)
            // Q_bar = NOR(S, Q)
            nor #1 (Q[i],     R, Q_bar[i]);
            nor #1 (Q_bar[i], S, Q[i]);
        end
    endgenerate

    assign count = Q;

endmodule
```

