# 순수 조합 논리 기반 8비트 카운터 설계

## 서론: 근본적 모순과 해결 방향

순차 논리 요소를 배제하면서 상태를 기억하는 카운터를 구현하는 것은 **디지털 논리 설계의 근본 원리와 상충**됩니다. 이 문제를 해결하기 위해 두 가지 접근법을 제시합니다.

---

## 접근법 1: 조합 논리 피드백 루프 (Combinational Feedback Loop)

### 핵심 원리: 비안정 멀티바이브레이터 특성을 이용한 래치 구성

클럭 없이 상태를 유지하려면 **SR 래치(SR Latch)** 를 조합 논리 게이트만으로 구성합니다. SR 래치는 NAND 또는 NOR 게이트의 **교차 결합(Cross-Coupled) 피드백** 구조로, 클럭 신호 없이 정적 상태(Static State)를 유지하는 **비동기 쌍안정 소자(Asynchronous Bistable Element)** 입니다.

```verilog
//==========================================================
// 파일명: combinational_counter.v
// 설명: 순수 조합 논리 게이트만을 사용한 8비트 카운터
//       SR 래치(NAND 기반) 피드백 루프로 상태 저장
//       클럭, D-FF, always @(posedge clk) 등 일체 사용 금지
//==========================================================

//----------------------------------------------------------
// 모듈 1: NAND 기반 SR 래치 (1비트 상태 저장 단위)
// 원리: 두 NAND 게이트의 출력이 상호 입력으로 교차 결합됨
//       S=0, R=1 → Q=1 (Set 상태)
//       S=1, R=0 → Q=0 (Reset 상태)
//       S=1, R=1 → Q 유지 (Hold 상태 = 이전 상태 보존)
//----------------------------------------------------------
module sr_latch_nand (
    input  wire S_n,   // Active-Low Set 입력
    input  wire R_n,   // Active-Low Reset 입력
    output wire Q,     // 정출력
    output wire Q_n    // 부출력
);
    // 교차 결합 NAND 게이트 피드백 루프
    // nand 프리미티브: 순수 조합 논리 게이트 인스턴스
    nand #(1) gate_upper (Q,   S_n, Q_n);  // 전파 지연 1단위
    nand #(1) gate_lower (Q_n, R_n, Q  );  // 전파 지연 1단위
    // 주의: S_n=0, R_n=0 동시 인가 시 메타스테이블(Metastable) 상태 발생
endmodule


//----------------------------------------------------------
// 모듈 2: NAND SR 래치 기반 D 래치 (게이트 제어 래치)
// 원리: Enable(EN) 신호가 High일 때 D 입력을 투과(Transparent)
//       Enable이 Low일 때 마지막 D 값을 래치(Latch) 상태로 유지
// 구현: D와 EN의 NAND → S_n / D_bar와 EN의 NAND → R_n
//----------------------------------------------------------
module d_latch_combinational (
    input  wire D,    // 데이터 입력
    input  wire EN,   // 투과 제어 신호 (Active-High)
    output wire Q,    // 래치 출력
    output wire Q_n   // 래치 부출력
);
    wire S_n, R_n, D_n;

    // D의 논리 보수 생성 (NOT = 단입력 NAND)
    nand #(1) inv_d    (D_n, D,   D  );  // NOT 게이트 등가
    // S_n, R_n 생성
    nand #(1) nand_s   (S_n, D,   EN );  // S_n = NAND(D, EN)
    nand #(1) nand_r   (R_n, D_n, EN );  // R_n = NAND(D_bar, EN)

    // SR 래치 인스턴스
    sr_latch_nand latch_core (
        .S_n (S_n),
        .R_n (R_n),
        .Q   (Q  ),
        .Q_n (Q_n)
    );
endmodule


//----------------------------------------------------------
// 모듈 3: 1비트 반가산기 (Half Adder)
// 순수 조합 논리: XOR(합), AND(올림수)
//----------------------------------------------------------
module half_adder (
    input  wire A,
    input  wire B,
    output wire Sum,
    output wire Cout
);
    xor (Sum,  A, B);
    and (Cout, A, B);
endmodule


//----------------------------------------------------------
// 모듈 4: 1비트 전가산기 (Full Adder)
// 두 개의 반가산기와 OR 게이트로 구성
//----------------------------------------------------------
module full_adder (
    input  wire A,
    input  wire B,
    input  wire Cin,
    output wire Sum,
    output wire Cout
);
    wire sum1, carry1, carry2;

    half_adder ha1 (.A(A),    .B(B),    .Sum(sum1),  .Cout(carry1));
    half_adder ha2 (.A(sum1), .B(Cin),  .Sum(Sum),   .Cout(carry2));
    or  (Cout, carry1, carry2);
endmodule


//----------------------------------------------------------
